class Solution {
    public void sortColors(int[] numbers) {
        // Pointers define the boundaries for red (0), white (1), and blue (2) sections.
        int redSectionEnd = 0;
        int blueSectionStart = numbers.length - 1;
        int currentUnknownIndex = 0;

        while (currentUnknownIndex <= blueSectionStart) {
            if (numbers[currentUnknownIndex] == 0) { // 0 represents red
                // If a red element is found, it must be moved to the front (red section).
                swap(numbers, currentUnknownIndex, redSectionEnd);
                redSectionEnd++;
                currentUnknownIndex++;
            } else if (numbers[currentUnknownIndex] == 2) { // 2 represents blue
                // If a blue element is found, it must be moved to the back (blue section).
                swap(numbers, currentUnknownIndex, blueSectionStart);
                blueSectionStart--;
            } else { // 1 represents white
                // A white element is in the correct partition for now, so we can just advance.
                currentUnknownIndex++;
            }
        }
    }

    private void swap(int[] numbers, int firstIndex, int secondIndex) {
        int temporaryValue = numbers[firstIndex];
        numbers[firstIndex] = numbers[secondIndex];
        numbers[secondIndex] = temporaryValue;
    }
}

